var input = inputs.Length > 0 && inputs[0] != null ? inputs[0]! :
        new PixelBuffer(context.TileSize, context.TileSize);
    var mode = GetChoice(parameters, "mode", "outside");
    var lineColor = GetColor(parameters, "lineColor", Colors.Black);
    var thickness = Math.Max(1, GetInt(parameters, "thickness", 1));
    var cornerMode = GetChoice(parameters, "corner", "sharp");
    var threshold = GetFloat(parameters, "threshold", 0.5f);
    var detectMode = GetChoice(parameters, "detectMode", "alpha");
    var opacity = GetFloat(parameters, "opacity", 1f);

    var size = context.TileSize;
    var output = input.Clone();

    var lR = lineColor.R / 255f;
    var lG = lineColor.G / 255f;
    var lB = lineColor.B / 255f;

    // Step 1: Compute pixel-perfect edge mask
    var edgeMask = ComputeCrispEdges(input, size, threshold, detectMode, cornerMode, mode);

    // Step 2: Dilate for thickness
    if (thickness > 1)
        edgeMask = DilateEdges(edgeMask, size, thickness);

    // Step 3: Apply outline colors
    output.ParallelForEachPixel((x, y) =>
    {
        var edge = edgeMask[y * size + x];
        if (edge <= 0f) return;

        var (r, g, b, a) = output.GetPixel(x, y);

        if (mode == "outside")
        {
            // Replace pixels outside the sprite with the outline color
            output.SetPixel(x, y, lR, lG, lB, edge * opacity);
        }
        else if (mode == "inside")
        {
            // Blend outline over interior of the sprite
            var alpha = Math.Min(1f, edge * opacity);
            output.SetPixel(x, y,
                Lerp(r, lR, alpha),
                Lerp(g, lG, alpha),
                Lerp(b, lB, alpha),
                Math.Max(a, alpha));
        }
        else // both
        {
            // Blend outline everywhere (replaces alpha for outside, blends for inside)
            if (a < 0.5f)
                output.SetPixel(x, y, lR, lG, lB, edge * opacity);
            else
            {
                var alpha = Math.Min(1f, edge * opacity);
                output.SetPixel(x, y,
                    Lerp(r, lR, alpha),
                    Lerp(g, lG, alpha),
                    Lerp(b, lB, alpha),
                    Math.Max(a, alpha));
            }
        }
    });

    return output;

private static float[] ComputeCrispEdges(PixelBuffer input, int size, float threshold, string detectMode, string cornerMode, string outlineMode)
{
    var edges = new float[size * size];
    var useDiagonal = cornerMode != "sharp";
    var detectOuter = outlineMode == "outside" || outlineMode == "both";
    var detectInner = outlineMode == "inside" || outlineMode == "both";

    // Precompute detection values so each pixel is sampled only once
    var values = new float[size * size];
    for (var y = 0; y < size; y++)
    {
        for (var x = 0; x < size; x++)
        {
            values[y * size + x] = GetDetectionValue(input, x, y, detectMode);
        }
    }

    // First pass: detect edge pixels
    for (var y = 0; y < size; y++)
    {
        for (var x = 0; x < size; x++)
        {
            var centerVal = values[y * size + x];
            var isInside = centerVal > threshold;

            // Check cardinal neighbors
            var hasOppositeCardinal = false;
            var hasOppositeDiagonal = false;

            // Cardinal directions
            var nInside = IsInside(values, size, x - 1, y, threshold);
            var eInside = IsInside(values, size, x + 1, y, threshold);
            var sInside = IsInside(values, size, x, y - 1, threshold);
            var wInside = IsInside(values, size, x, y + 1, threshold);

            if (nInside != isInside || eInside != isInside || sInside != isInside || wInside != isInside)
                hasOppositeCardinal = true;

            // Diagonal neighbors
            if (useDiagonal)
            {
                var nwInside = IsInside(values, size, x - 1, y - 1, threshold);
                var neInside = IsInside(values, size, x + 1, y - 1, threshold);
                var swInside = IsInside(values, size, x - 1, y + 1, threshold);
                var seInside = IsInside(values, size, x + 1, y + 1, threshold);

                if (nwInside != isInside || neInside != isInside || swInside != isInside || seInside != isInside)
                    hasOppositeDiagonal = true;
            }

            var isEdge = false;

            if (detectOuter && !isInside && hasOppositeCardinal)
                isEdge = true;
            if (detectInner && isInside && hasOppositeCardinal)
                isEdge = true;

            // Extended detection with diagonal neighbors
            if (!isEdge && useDiagonal)
            {
                if (detectOuter && !isInside && hasOppositeDiagonal)
                    isEdge = true;
                if (detectInner && isInside && hasOppositeDiagonal)
                    isEdge = true;
            }

            edges[y * size + x] = isEdge ? 1f : 0f;
        }
    }

    // Corner rounding pass: fill L-shaped corner gaps for "rounded"
    if (cornerMode == "rounded")
    {
        for (var y = 0; y < size; y++)
        {
            for (var x = 0; x < size; x++)
            {
                if (edges[y * size + x] > 0f) continue;

                // Check 2x2 blocks for concave corner patterns.
                // A pixel gets filled if it would round out a 90-degree corner:
                // two orthogonal edge pixels on adjacent sides with a diagonal
                // edge pixel opposite.
                var tl = GetEdge(edges, size, x - 1, y - 1);
                var t = GetEdge(edges, size, x, y - 1);
                var tr = GetEdge(edges, size, x + 1, y - 1);
                var l = GetEdge(edges, size, x - 1, y);
                var r = GetEdge(edges, size, x + 1, y);
                var bl = GetEdge(edges, size, x - 1, y + 1);
                var b = GetEdge(edges, size, x, y + 1);
                var br = GetEdge(edges, size, x + 1, y + 1);

                // Detect L-shaped corner: two adjacent cardinals + their shared diagonal
                // e.g., pixel is at the outer corner of an inside block
                if ((l > 0f && t > 0f && tl > 0f) ||
                    (r > 0f && t > 0f && tr > 0f) ||
                    (l > 0f && b > 0f && bl > 0f) ||
                    (r > 0f && b > 0f && br > 0f))
                {
                    edges[y * size + x] = 1f;
                }
            }
        }
    }

    return edges;
}

private static bool IsInside(float[] values, int size, int x, int y, float threshold)
{
    // Wrap around for tileable
    x = ((x % size) + size) % size;
    y = ((y % size) + size) % size;
    return values[y * size + x] > threshold;
}

private static float GetEdge(float[] edges, int size, int x, int y)
{
    x = ((x % size) + size) % size;
    y = ((y % size) + size) % size;
    return edges[y * size + x];
}

private static float GetDetectionValue(PixelBuffer input, int x, int y, string detectMode)
{
    var (r, g, b, a) = input.GetPixel(x, y);
    return detectMode switch
    {
        "alpha" => a,
        "luminance" => r * 0.299f + g * 0.587f + b * 0.114f,
        _ => (r + g + b) / 3f
    };
}

private static float[] DilateEdges(float[] edges, int size, int thickness)
{
    if (thickness <= 1) return edges;
    var temp = new float[size * size];
    var src = edges;
    var dst = temp;

    for (var iter = 1; iter < thickness; iter++)
    {
        Array.Clear(dst);

        for (var y = 0; y < size; y++)
        {
            for (var x = 0; x < size; x++)
            {
                if (src[y * size + x] > 0f)
                {
                    dst[y * size + x] = 1f;
                    continue;
                }

                // Check all 8 neighbors for dilation
                for (var dy = -1; dy <= 1; dy++)
                {
                    for (var dx = -1; dx <= 1; dx++)
                    {
                        if (dx == 0 && dy == 0) continue;
                        var nx = (x + dx + size) % size;
                        var ny = (y + dy + size) % size;
                        if (src[ny * size + nx] > 0f)
                        {
                            dst[y * size + x] = 1f;
                            goto next;
                        }
                    }
                }
                next:;
            }
        }

        (src, dst) = (dst, src);
    }

    if (thickness % 2 == 0)
    {
        Array.Copy(temp, edges, temp.Length);
    }

    return edges;
    }
}
